{
  "grammar": [
    {
      "pattern": "Subject + 請 + 再 + 說 + 一次 + Object",
      "structure": ["Subject", "請", "再", "說", "一次", "Object"],
      "explanation_en": "Use this pattern to politely ask someone to repeat what they said. It's a common repair strategy in conversations.",
      "title": "請再說一次 (Please Say It Again)",
      "meaning": "Politely asking for repetition",
      "when_to_use": ["When you didn't hear clearly", "When you didn't understand", "When you need confirmation"],
      "when_not_to_use": ["When you understand perfectly", "When you want to challenge someone", "In very formal written contexts"],
      "pragmatic_notes": "In Taiwan, adding '不好意思' before this phrase makes it even more polite. It's very common in service encounters.",
      "word_order_notes": "The adverb '再' must come before the verb '說'. The object can be omitted if clear from context.",
      "english_contrast": "English uses 'Could you say that again?' while Chinese uses '請再說一次' with a fixed word order.",
      "korean_contrast": "Korean uses '다시 한 번 말씀해 주세요' which is similar but often includes honorifics.",
      "negative_examples": [
        {
          "text": "請說一次再。",
          "error": "'再' must come before '說', not after."
        }
      ],
      "incorrect_examples": [
        {
          "text": "請說一次再。",
          "error": "'再' must come before '說', not after."
        }
      ],
      "transformation_drills": ["Change '請' to '不好意思' to make it more polite.", "Add '可以嗎' at the end to make it a question."],
      "production_drills": ["Ask your partner to repeat a sentence you didn't hear.", "Role-play a situation where you ask a store clerk to repeat the price."],
      "common_error_patterns": ["Placing '再' after the verb", "Forgetting '請' in polite contexts"],
      "repair_feedback": {
        "word_order": "Remember: 再 + verb, not verb + 再.",
        "politeness": "Always include 請 or 不好意思 in service situations.",
        "vocabulary": "Use 一次 for 'one time', not 一遍 (which is for complete actions)."
      }
    },
    {
      "pattern": "Subject + 請 + 說 + 慢 + 一點",
      "structure": ["Subject", "請", "說", "慢", "一點"],
      "explanation_en": "Use this pattern to ask someone to speak more slowly. It's a polite way to manage conversation pace.",
      "title": "慢一點 (Speak More Slowly)",
      "meaning": "Requesting slower speech",
      "when_to_use": ["When the speaker is too fast", "When you need processing time", "When learning a new language"],
      "when_not_to_use": ["When you are in a hurry", "When the speaker is already slow", "In very urgent situations"],
      "pragmatic_notes": "In Taiwan, it's common to add '不好意思' before this request. It's seen as a sign of diligence, not weakness.",
      "word_order_notes": "The adjective '慢' comes after the verb '說' and before '一點'. This is a resultative complement structure.",
      "english_contrast": "English says 'speak more slowly' with an adverb, while Chinese uses '說慢一點' with an adjective + 一點.",
      "korean_contrast": "Korean uses '좀 천천히 말해 주세요' which is similar but uses an adverb form.",
      "negative_examples": [
        {
          "text": "請慢說一點。",
          "error": "'慢' must come after '說', not before."
        }
      ],
      "incorrect_examples": [
        {
          "text": "請慢說一點。",
          "error": "'慢' must come after '說', not before."
        }
      ],
      "transformation_drills": ["Replace '說' with '講' for a more casual tone.", "Add '可以嗎' to make it a question."],
      "production_drills": ["Ask a teacher to speak more slowly during class.", "Role-play asking a friend to slow down on the phone."],
      "common_error_patterns": ["Placing '慢' before the verb", "Using '很慢' instead of '慢一點'"],
      "repair_feedback": {
        "word_order": "Remember: verb + 慢 + 一點, not 慢 + verb.",
        "politeness": "Always use 請 or 不好意思 in formal settings.",
        "vocabulary": "Use 一點 for 'a little', not 一些 (which is for quantity)."
      }
    },
    {
      "pattern": "Subject + 是不是 + [statement] + 的意思",
      "structure": ["Subject", "是不是", "statement", "的意思"],
      "explanation_en": "Use this pattern to confirm your understanding of what someone said. It's a clarification check.",
      "title": "是不是...的意思 (Is It That...?)",
      "meaning": "Confirming understanding",
      "when_to_use": ["When you want to check if you understood correctly", "When paraphrasing someone's words", "When resolving a misunderstanding"],
      "when_not_to_use": ["When you are certain of the meaning", "When you want to challenge someone", "In very casual chats with close friends (use '是說' instead)"],
      "pragmatic_notes": "In Taiwan, this pattern is very common in both formal and informal settings. It shows you are actively listening.",
      "word_order_notes": "The phrase '是不是' comes before the statement, and '的意思' comes after. The subject can be omitted if clear.",
      "english_contrast": "English uses 'Do you mean that...?' while Chinese uses '是不是...的意思' with a fixed structure.",
      "korean_contrast": "Korean uses '...라는 뜻인가요?' which is similar but often uses question endings.",
      "negative_examples": [
        {
          "text": "是不是的意思你？",
          "error": "'的意思' must come after the statement, not before the subject."
        }
      ],
      "incorrect_examples": [
        {
          "text": "是不是的意思你？",
          "error": "'的意思' must come after the statement, not before the subject."
        }
      ],
      "transformation_drills": ["Replace '是不是' with '是說' for a more casual tone.", "Add '嗎' at the end to make it a yes/no question."],
      "production_drills": ["Confirm with a partner that you understood their instructions correctly.", "Role-play clarifying a misunderstanding about a meeting time."],
      "common_error_patterns": ["Placing '的意思' before the statement", "Forgetting '的意思' at the end"],
      "repair_feedback": {
        "word_order": "Remember: 是不是 + statement + 的意思.",
        "politeness": "Use 請問 before this pattern in formal contexts.",
        "vocabulary": "Use 意思 for 'meaning', not 意義 (which is more abstract)."
      }
    }
  ]
}
